package main

import "fmt"

func square(x int) int {
	return x * x
}

func add(a int, b int) int {
	return a + b
}

// Birden fazla deger dondurme
func divide(a int, b int) (int, int) {
	quotient := a / b
	remainder := a % b
	return quotient, remainder
}

// Named return values
func minMax(numbers []int) (min int, max int) {
	min = numbers[0]
	max = numbers[0]

	for _, n := range numbers {
		if n < min {
			min = n
		}
		if n > max {
			max = n
		}
	}
	return
}

// Variadic fonksiyon
func sum(numbers ...int) int {
	total := 0
	for _, n := range numbers {
		total += n
	}
	return total
}

func main() {
	fmt.Println("Kare:", square(5))
	fmt.Println("Toplam:", add(3, 7))

	q, r := divide(17, 5)
	fmt.Println("\n17 / 5 -> bolum:", q, ", kalan:", r)

	min, max := minMax([]int{4, 12, 7, 23, 9, 1})
	fmt.Println("\nMin:", min, ", Max:", max)

	fmt.Println("\nVariadic toplam:", sum(1, 2, 3, 4, 5))
}
